#include <stdio.h>
#include <string.h>
int main() {
    int N, Q, R;
    char S[100001][11], P[11];
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        scanf("%s", S[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d %s", &R, P);
        char ans[11] = {0};
        int max_len = 0;
        for (int j = 0; j < R; j++) {
            int len = 0;
            while (len < strlen(P) && len < strlen(S[j]) && P[len] == S[j][len]) {
                len++;
            }
            if (len > max_len) {
                max_len = len;
                strcpy(ans, S[j]);
            } else if (len == max_len && strcmp(ans, S[j]) > 0) {
                strcpy(ans, S[j]);
            }
        }
        printf("%s\n", ans);
    }
    return 0;
}

