import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        String[] S = new String[N];
        for (int i = 0; i < N; i++) {
            S[i] = sc.next();
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int R = sc.nextInt();
            String P = sc.next();
            String ans = "";
            int max_len = 0;
            for (int j = 0; j < R; j++) {
                int len = 0;
                while (len < P.length() && len < S[j].length() && P.charAt(len) == S[j].charAt(len)) {
                    len++;
                }
                if (len > max_len) {
                    max_len = len;
                    ans = S[j];
                } else if (len == max_len && ans.compareTo(S[j]) > 0) {
                    ans = S[j];
                }
            }
            System.out.println(ans);
        }
    }
}

